// ─── CLOUDINARY CONFIG ────────────────────────────────────────────────────────
const CLOUDINARY_CLOUD  = "djq8rwwsw";
const CLOUDINARY_PRESET = "Fairway";
const CLOUDINARY_URL    = `https://api.cloudinary.com/v1_1/${CLOUDINARY_CLOUD}/image/upload`;

// Upload vers Cloudinary — accepte un File (HEIC/JPG/PNG/…) ou un data URL base64
// HEIC → JPG converti automatiquement par Cloudinary via f_jpg dans l'URL de retour
async function uploadPhoto(fileOrBase64, folder = "fairway") {
  // Déjà une URL http → rien à faire
  if (!fileOrBase64) return null;
  if (typeof fileOrBase64 === "string" && fileOrBase64.startsWith("http")) return fileOrBase64;

  const formData = new FormData();
  formData.append("upload_preset", CLOUDINARY_PRESET);
  formData.append("folder", folder);

  if (fileOrBase64 instanceof File) {
    // ✅ Fichier binaire direct (HEIC, JPEG, PNG…) — méthode la plus fiable
    formData.append("file", fileOrBase64);
  } else if (typeof fileOrBase64 === "string" && fileOrBase64.startsWith("data:")) {
    // data URL base64 (fallback avatar)
    formData.append("file", fileOrBase64);
  } else {
    return fileOrBase64;
  }

  const res = await fetch(CLOUDINARY_URL, { method: "POST", body: formData });
  if (!res.ok) {
    const errText = await res.text();
    throw new Error(`Cloudinary ${res.status}: ${errText}`);
  }
  const data = await res.json();
  if (data.error) throw new Error(data.error.message);

  // Transformation Cloudinary : f_jpg = HEIC→JPG, q_auto = qualité auto, w_1200 = max largeur
  return data.secure_url.replace("/upload/", "/upload/f_jpg,q_auto,w_1200/");
}

// ─── HELPERS FIREBASE ────────────────────────────────────────────────────────
const col    = (path) => collection(db, path);
const docRef = (path) => doc(db, path);

async function fbSet(path, data)   { await setDoc(doc(db, path), data, { merge: true }); }
async function fbDel(path)         { await deleteDoc(doc(db, path)); }
async function fbGet(path)         { const d = await getDoc(doc(db, path)); return d.exists() ? d.data() : null; }

// ─── TEAMS HELPERS ───────────────────────────────────────────────────────────
async function createTeam(name, creatorUid) {
  const id = `team_${Date.now()}`;
  const now = new Date().toISOString();
  await fbSet(`teams/${id}`, { id, name, memberIds: [creatorUid], createdAt: now });
  // membership log
  await fbSet(`memberships/${id}_${creatorUid}`, { userId: creatorUid, teamId: id, addedByUserId: creatorUid, joinedAt: now });
  // mettre à jour teamsIds de l'utilisateur
  await updateDoc(doc(db, `users/${creatorUid}`), { teamsIds: arrayUnion(id) });
  return id;
}
// Ajoute un membre à une team (par un membre existant)
async function addMemberToTeam(teamId, targetUid, byUid) {
  const now = new Date().toISOString();
  await updateDoc(doc(db, `teams/${teamId}`), { memberIds: arrayUnion(targetUid) });
  await fbSet(`memberships/${teamId}_${targetUid}`, { userId: targetUid, teamId, addedByUserId: byUid, joinedAt: now });
  await updateDoc(doc(db, `users/${targetUid}`), { teamsIds: arrayUnion(teamId) });
}
// Quitter une team (l'équipe reste existante)
async function leaveTeam(teamId, uid) {
  await updateDoc(doc(db, `teams/${teamId}`), { memberIds: arrayRemove(uid) });
  await updateDoc(doc(db, `users/${uid}`), { teamsIds: arrayRemove(teamId) });
  // log membership conservé pour traçabilité
}
// Supprimer définitivement une team (créateur uniquement)
async function deleteTeam(teamId, uid) {
  await fbDel(`teams/${teamId}`);
  await updateDoc(doc(db, `users/${uid}`), { teamsIds: arrayRemove(teamId) });
}
// Durée d'expiration des notifs = date du créneau + 1 jour
function notifExpiresAt(slotDate) {
  const d = new Date(slotDate + "T23:59:59");
  d.setDate(d.getDate() + 1);
  return d.toISOString();
}
// Filtre les notifs non expirées
function isNotifActive(notif) {
  if (!notif.expiresAt) return true; // rétrocompat
  return new Date() < new Date(notif.expiresAt);
}

